CREATE TABLE students (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    age INTEGER,
    grade REAL,
    email TEXT
);

INSERT INTO students (name, age, grade, email) VALUES
    ('Ahmet Yilmaz', 20, 85.50, 'ahmet@example.com'),
    ('Ayse Kaya', 21, 92.00, 'ayse@example.com'),
    ('Mehmet Demir', 22, 67.25, 'mehmet@example.com'),
    ('Zeynep Sahin', 19, 78.75, 'zeynep@example.com'),
    ('Can Ozturk', 23, 55.00, 'can@example.com');

-- Tek kolona index ekleme
CREATE INDEX idx_students_grade ON students(grade);

-- Birden fazla kolona index (composite index)
CREATE INDEX idx_students_age_grade ON students(age, grade);

-- Unique index (benzersizlik garantisi)
CREATE UNIQUE INDEX idx_students_email ON students(email);

-- Index'leri listeleme (SQLite: pragma kullanilir)
PRAGMA index_list(students);

-- Sorgu plani inceleme (EXPLAIN QUERY PLAN ile)
EXPLAIN QUERY PLAN
SELECT * FROM students WHERE grade > 70;

-- Index kullanan sorgu (grade kolonunda index var)
SELECT name, grade FROM students
WHERE grade > 70
ORDER BY grade DESC;

-- Index'i silme
DROP INDEX idx_students_grade;

-- Index'lerin onemi: buyuk tablolarda WHERE, JOIN ve
-- ORDER BY kullanilan kolonlara index eklemek
-- sorgu hizini onemli olcude artirir.
